131	// updateOriginalKubeConfigwithNodeConfig updates the original Kubelet Configuration based on the Nodespecific configuration
132	func updateOriginalKubeConfigwithNodeConfig(node *osev1.Node, originalKubeletConfig *kubeletconfigv1beta1.KubeletConfiguration) error {
133		// updating the kubelet specific fields based on the Node's workerlatency profile.
134		// (TODO): The durations can be replaced with the defined constants in the openshift/api repository once the respective changes are merged.
135		switch node.Spec.WorkerLatencyProfile {
136		case osev1.MediumUpdateAverageReaction:
137			originalKubeletConfig.NodeStatusUpdateFrequency = metav1.Duration{Duration: osev1.MediumNodeStatusUpdateFrequency}
138		case osev1.LowUpdateSlowReaction:
139			originalKubeletConfig.NodeStatusUpdateFrequency = metav1.Duration{Duration: osev1.LowNodeStatusUpdateFrequency}
140		case osev1.DefaultUpdateDefaultReaction:
141			originalKubeletConfig.NodeStatusUpdateFrequency = metav1.Duration{Duration: osev1.DefaultNodeStatusUpdateFrequency}
142		case emptyInput:
143			return nil
144		default:
145			return fmt.Errorf("unknown worker latency profile type found %v, failed to update the original kubelet configuration", node.Spec.WorkerLatencyProfile)
146		}
147		// The kubelet configuration can be updated based on the cgroupmode as well here.
148		return nil
149	}
