151	// updateMachineConfigwithCgroup updates the Machine Config object based on the cgroup mode present in the Config Node resource.
152	func updateMachineConfigwithCgroup(node *osev1.Node, mc *mcfgv1.MachineConfig) error {
153		// updating the Machine Config resource with the relevant cgroup config
154		var (
155			kernelArgsv1                                            = []string{"systemd.unified_cgroup_hierarchy=0", "systemd.legacy_systemd_cgroup_controller=1"}
156			kernelArgsv2                                            = []string{"systemd.unified_cgroup_hierarchy=1", "cgroup_no_v1=\"all\""}
157			kernelArgsToAdd, kernelArgsToRemove, adjustedKernelArgs []string
158		)
159		switch node.Spec.CgroupMode {
160		case osev1.CgroupModeV2, osev1.CgroupModeEmpty:
161			kernelArgsToAdd = append(kernelArgsToAdd, kernelArgsv2...)
162			kernelArgsToRemove = append(kernelArgsToRemove, kernelArgsv1...)
163		default:
164			return fmt.Errorf("unknown cgroup mode found %v, failed to update the machine config resource", node.Spec.CgroupMode)
165		}
166	
167		for _, arg := range mc.Spec.KernelArguments {
168			// only append the args we want to keep, omitting the undesired
169			if !ctrlcommon.InSlice(arg, kernelArgsToRemove) {
170				adjustedKernelArgs = append(adjustedKernelArgs, arg)
171			}
172		}
173	
174		for _, arg := range kernelArgsToAdd {
175			// add the additional that aren't already there
176			if !ctrlcommon.InSlice(arg, adjustedKernelArgs) {
177				adjustedKernelArgs = append(adjustedKernelArgs, arg)
178			}
179		}
180		// overwrite the KernelArguments with the adjusted KernelArgs
181		mc.Spec.KernelArguments = adjustedKernelArgs
182		return nil
183	}
