185	func findKubeletConfig(mc *mcfgv1.MachineConfig) (*ign3types.File, error) {
186		ignCfg, err := ctrlcommon.ParseAndConvertConfig(mc.Spec.Config.Raw)
187		if err != nil {
188			return nil, fmt.Errorf("parsing Kubelet Ignition config failed with error: %w", err)
189		}
190		for _, c := range ignCfg.Storage.Files {
191			if c.Path == "/etc/kubernetes/kubelet.conf" {
192				return &c, nil
193			}
194		}
195		return nil, fmt.Errorf("could not find Kubelet Config")
196	}
