323	func notLatestKubeletConfigInPool(kcList []mcfgv1.KubeletConfig, cfg *mcfgv1.KubeletConfig) bool {
324		for _, kc := range kcList {
325			if kc.CreationTimestamp.Compare(cfg.CreationTimestamp.Time) > 0 {
326				return true
327			}
328		}
329		return false
330	}
