401	func wrapErrorWithCondition(err error, args ...interface{}) mcfgv1.KubeletConfigCondition {
402		var condition *mcfgv1.KubeletConfigCondition
403		if err != nil {
404			condition = apihelpers.NewKubeletConfigCondition(
405				mcfgv1.KubeletConfigFailure,
406				corev1.ConditionTrue,
407				fmt.Sprintf("Error: %v", err),
408			)
409		} else {
410			condition = apihelpers.NewKubeletConfigCondition(
411				mcfgv1.KubeletConfigSuccess,
412				corev1.ConditionTrue,
413				"Success",
414			)
415		}
416		if len(args) > 0 {
417			format, ok := args[0].(string)
418			if ok {
419				condition.Message = fmt.Sprintf(format, args[1:]...)
420			}
421		}
422		return *condition
423	}
