425	func DecodeKubeletConfig(data []byte) (*kubeletconfigv1beta1.KubeletConfiguration, error) {
426		config := &kubeletconfigv1beta1.KubeletConfiguration{}
427		d := yaml.NewYAMLOrJSONDecoder(bytes.NewReader(data), len(data))
428		if err := d.Decode(config); err != nil {
429			return nil, err
430		}
431		return config, nil
432	}
433	
434	func EncodeKubeletConfig(internal *kubeletconfigv1beta1.KubeletConfiguration, targetVersion schema.GroupVersion, contentType string) ([]byte, error) {
435		encoder, err := newKubeletconfigJSONEncoder(targetVersion, contentType)
436		if err != nil {
437			return nil, err
438		}
439		data, err := runtime.Encode(encoder, internal)
440		if err != nil {
441			return nil, err
442		}
443		return data, nil
444	}
445	
446	func newKubeletconfigJSONEncoder(targetVersion schema.GroupVersion, contentType string) (runtime.Encoder, error) {
447		scheme := runtime.NewScheme()
448		kubeletconfigv1beta1.AddToScheme(scheme)
449		codecs := serializer.NewCodecFactory(scheme)
450		info, ok := runtime.SerializerInfoForMediaType(codecs.SupportedMediaTypes(), contentType)
451		if !ok {
452			return nil, fmt.Errorf("unsupported media type %q", contentType)
453		}
454		return codecs.EncoderForVersion(info.Serializer, targetVersion), nil
455	}
