457	// kubeletConfigToIgnFile converts a KubeletConfiguration to an Ignition File
458	func kubeletConfigToIgnFile(cfg *kubeletconfigv1beta1.KubeletConfiguration) (*ign3types.File, error) {
459		cfgJSON, err := EncodeKubeletConfig(cfg, kubeletconfigv1beta1.SchemeGroupVersion, runtime.ContentTypeYAML)
460		if err != nil {
461			return nil, fmt.Errorf("could not encode kubelet configuration: %w", err)
462		}
463		cfgIgn := createNewKubeletIgnition(cfgJSON)
464		return cfgIgn, nil
465	}
