467	// generateKubeletIgnFiles generates the Ignition files from the kubelet config
468	func generateKubeletIgnFiles(kubeletConfig *mcfgv1.KubeletConfig, originalKubeConfig *kubeletconfigv1beta1.KubeletConfiguration) (*ign3types.File, *ign3types.File, *ign3types.File, error) {
469		var (
470			kubeletIgnition            *ign3types.File
471			logLevelIgnition           *ign3types.File
472			autoSizingReservedIgnition *ign3types.File
473		)
474		userDefinedSystemReserved := make(map[string]string)
475	
476		if kubeletConfig.Spec.KubeletConfig != nil && kubeletConfig.Spec.KubeletConfig.Raw != nil {
477			specKubeletConfig, err := DecodeKubeletConfig(kubeletConfig.Spec.KubeletConfig.Raw)
478			if err != nil {
479				return nil, nil, nil, fmt.Errorf("could not deserialize the new Kubelet config: %w", err)
480			}
481	
482			if val, ok := specKubeletConfig.SystemReserved["memory"]; ok {
483				userDefinedSystemReserved["memory"] = val
484				delete(specKubeletConfig.SystemReserved, "memory")
485			}
486	
487			if val, ok := specKubeletConfig.SystemReserved["cpu"]; ok {
488				userDefinedSystemReserved["cpu"] = val
489				delete(specKubeletConfig.SystemReserved, "cpu")
490			}
491	
492			if val, ok := specKubeletConfig.SystemReserved["ephemeral-storage"]; ok {
493				userDefinedSystemReserved["ephemeral-storage"] = val
494				delete(specKubeletConfig.SystemReserved, "ephemeral-storage")
495			}
496	
497			// FeatureGates must be set from the FeatureGate.
498			// Remove them here to prevent the specKubeletConfig merge overwriting them.
499			specKubeletConfig.FeatureGates = nil
500	
501			// "protectKernelDefaults" is a boolean, optional field with `omitempty` json tag in the upstream kubelet configuration
502			// This field has been set to `true` by default in OCP recently
503			// As this field is an optional one with the above tag, it gets omitted when a user inputs it to `false`
504			// Reference: https://github.com/golang/go/issues/13284
505			// Adding a workaround to decide if the user has actually set the field to `false`
506			if strings.Contains(string(kubeletConfig.Spec.KubeletConfig.Raw), protectKernelDefaultsStr) {
507				originalKubeConfig.ProtectKernelDefaults = false
508			}
509			// Merge the Old and New
510			err = mergo.Merge(originalKubeConfig, specKubeletConfig, mergo.WithOverride)
511			if err != nil {
512				return nil, nil, nil, fmt.Errorf("could not merge original config and new config: %w", err)
513			}
514	
515			// Empty strings are ignored by mergo, so we need to set them to empty string for SystemReservedCgroup explicitly
516			// Else the old value is retained. Tested by test/e2e-2of2/kubeletcfg_test.go
517			// However, only clear it if the user explicitly sets enforceNodeAllocatable without system-reserved enforcement
518			if specKubeletConfig.SystemReservedCgroup == "" && len(specKubeletConfig.EnforceNodeAllocatable) > 0 {
519				// User explicitly set enforceNodeAllocatable - check if it contains system-reserved enforcement
520				hasSystemReservedEnforcement := false
521				for _, val := range specKubeletConfig.EnforceNodeAllocatable {
522					if val == kubeletypes.SystemReservedEnforcementKey || val == kubeletypes.SystemReservedCompressibleEnforcementKey {
523						hasSystemReservedEnforcement = true
524						break
525					}
526				}
527	
528				// Only clear systemReservedCgroup if user explicitly set enforceNodeAllocatable without system-reserved enforcement
529				// This prevents validation error: "systemReservedCgroup must be specified when system-reserved is in enforceNodeAllocatable"
530				if !hasSystemReservedEnforcement {
531					originalKubeConfig.SystemReservedCgroup = ""
532				}
533			}
534		}
535	
536		if originalKubeConfig.ReservedSystemCPUs != "" {
537			klog.Infof("reservedSystemCPUs is set to %s, disabling systemReservedCgroup enforcement", originalKubeConfig.ReservedSystemCPUs)
538			originalKubeConfig.SystemReservedCgroup = ""
539			// Filter out system-reserved enforcement keys and ensure pods is present
540			filtered := []string{}
541			hasPods := false
542			for _, val := range originalKubeConfig.EnforceNodeAllocatable {
543				// Skip system-reserved enforcement keys
544				if val == kubeletypes.SystemReservedEnforcementKey ||
545					val == kubeletypes.SystemReservedCompressibleEnforcementKey {
546					continue
547				}
548				if val == kubeletypes.NodeAllocatableEnforcementKey {
549					hasPods = true
550				}
551				filtered = append(filtered, val)
552			}
553			// Ensure pods enforcement is always present
554			if !hasPods {
555				filtered = append([]string{kubeletypes.NodeAllocatableEnforcementKey}, filtered...)
556			}
557			originalKubeConfig.EnforceNodeAllocatable = filtered
558		}
559	
560		if originalKubeConfig.SystemReservedCgroup != "" && originalKubeConfig.SystemCgroups != "" {
561			if originalKubeConfig.SystemReservedCgroup != originalKubeConfig.SystemCgroups {
562				return nil, nil, nil, fmt.Errorf("invalid merged configuration: systemReservedCgroup (%s) must match systemCgroups (%s)", originalKubeConfig.SystemReservedCgroup, originalKubeConfig.SystemCgroups)
563			}
564		}
565	
566		// Encode the new config into an Ignition File
567		kubeletIgnition, err := kubeletConfigToIgnFile(originalKubeConfig)
568		if err != nil {
569			return nil, nil, nil, fmt.Errorf("could not encode JSON: %w", err)
570		}
571	
572		if kubeletConfig.Spec.LogLevel != nil {
573			logLevelIgnition = createNewKubeletLogLevelIgnition(*kubeletConfig.Spec.LogLevel)
574		}
575		if kubeletConfig.Spec.AutoSizingReserved != nil && len(userDefinedSystemReserved) == 0 {
576			autoSizingReservedIgnition = createNewKubeletDynamicSystemReservedIgnition(kubeletConfig.Spec.AutoSizingReserved, userDefinedSystemReserved)
577		}
578		if len(userDefinedSystemReserved) > 0 {
579			autoSizingReservedIgnition = createNewKubeletDynamicSystemReservedIgnition(nil, userDefinedSystemReserved)
580		}
581	
582		return kubeletIgnition, logLevelIgnition, autoSizingReservedIgnition, nil
583	}
