165	// needsStorageUpdate returns true if the ContainerRuntimeConfig requires storage.conf changes.
166	func needsStorageUpdate(ctrcfg *mcfgv1.ContainerRuntimeConfiguration, additionalStorageEnabled bool) bool {
167		return (ctrcfg.OverlaySize != nil && !ctrcfg.OverlaySize.IsZero()) ||
168			(additionalStorageEnabled && (len(ctrcfg.AdditionalLayerStores) > 0 || len(ctrcfg.AdditionalImageStores) > 0))
169	}
170	
171	// needsCRIODropinUpdate returns true if the ContainerRuntimeConfig requires CRI-O drop-in file changes.
172	func needsCRIODropinUpdate(ctrcfg *mcfgv1.ContainerRuntimeConfiguration, additionalStorageEnabled bool) bool {
173		return ctrcfg.LogLevel != "" || ctrcfg.PidsLimit != nil ||
174			(ctrcfg.LogSizeMax != nil && !ctrcfg.LogSizeMax.IsZero()) ||
175			ctrcfg.DefaultRuntime != mcfgv1.ContainerRuntimeDefaultRuntimeEmpty ||
176			(additionalStorageEnabled && len(ctrcfg.AdditionalArtifactStores) > 0)
177	}
