179	// createNewIgnition takes a map where the key is the path of the file, and the value is the
180	// new data in the form of a byte array. The function returns the ignition config with the
181	// updated data.
182	func createNewIgnition(configs []generatedConfigFile) ign3types.Config {
183		tempIgnConfig := ctrlcommon.NewIgnConfig()
184		// Create ignitions
185		for _, ignConf := range configs {
186			// If the file is not included, the data will be nil so skip over
187			if ignConf.data == nil {
188				continue
189			}
190			configTempFile := ctrlcommon.NewIgnFileBytesOverwriting(ignConf.filePath, ignConf.data)
191			tempIgnConfig.Storage.Files = append(tempIgnConfig.Storage.Files, configTempFile)
192		}
193	
194		return tempIgnConfig
195	}
