255	// nolint: dupl
256	func getManagedKeyCtrCfg(pool *mcfgv1.MachineConfigPool, client mcfgclientset.Interface, cfg *mcfgv1.ContainerRuntimeConfig) (string, error) {
257		// Get all the ctrcfg CRs
258		ctrcfgListAll, err := client.MachineconfigurationV1().ContainerRuntimeConfigs().List(context.TODO(), metav1.ListOptions{})
259		if err != nil {
260			return "", fmt.Errorf("error listing container runtime configs: %w", err)
261		}
262		// If there is no ctrcfg in the list, return the default MC name with no suffix
263		if ctrcfgListAll == nil || len(ctrcfgListAll.Items) == 0 {
264			return ctrlcommon.GetManagedKey(pool, client, "99", "containerruntime", getManagedKeyCtrCfgDeprecated(pool))
265		}
266	
267		var ctrcfgList []mcfgv1.ContainerRuntimeConfig
268		for _, ctrcfg := range ctrcfgListAll.Items {
269			selector, err := metav1.LabelSelectorAsSelector(ctrcfg.Spec.MachineConfigPoolSelector)
270			if err != nil {
271				return "", fmt.Errorf("invalid label selector: %w", err)
272			}
273			if selector.Empty() || !selector.Matches(labels.Set(pool.Labels)) {
274				continue
275			}
276			ctrcfgList = append(ctrcfgList, ctrcfg)
277		}
278	
279		for _, ctrcfg := range ctrcfgList {
280			if ctrcfg.Name != cfg.Name {
281				continue
282			}
283			val, ok := ctrcfg.GetAnnotations()[ctrlcommon.MCNameSuffixAnnotationKey]
284			if !ok {
285				break
286			}
287			// if an MC name suffix exists, append it to the default MC name and return that as this containerruntime config exists and
288			// we are probably doing an update action on it
289			if val != "" {
290				return fmt.Sprintf("99-%s-generated-containerruntime-%s", pool.Name, val), nil
291			}
292			// if the suffix val is "", mc name should not suffixed the cfg to be updated is the first containerruntime config has been created
293			return ctrlcommon.GetManagedKey(pool, client, "99", "containerruntime", getManagedKeyCtrCfgDeprecated(pool))
294		}
295	
296		// If we are here, this means that
297		// 1. a new containerruntime config was created, so we have to calculate the suffix value for its MC name
298		// 2. or this is an existing containerruntime config did not get ctrlcommon.MCNameSuffixAnnotationKey set, so we have to set the MCNameSuffixAnnotationKey to the machineconfig suffix it was rendered to, assume for existing containerruntime config, cfg.Finalizers with the largest suffix is the machine config the ctrcfg was rendered to
299		// if the containerruntime config is the only one in the list, mc name should not suffixed since cfg is the first containerruntime config to be created
300		if len(ctrcfgList) == 1 {
301			return ctrlcommon.GetManagedKey(pool, client, "99", "containerruntime", getManagedKeyCtrCfgDeprecated(pool))
302		}
303		// if cfg is not a newly created containerruntime config and did not get ctrlcommon.MCNameSuffixAnnotationKey
304		// but has been rendered to a machineconfig, its len(cfg.Finalizers) > 0
305		if notLatestContainerRuntimeConfigInPool(ctrcfgList, cfg) {
306			finalizers := cfg.GetFinalizers()
307			containerRuntimeMCPrefix := fmt.Sprintf("99-%s-generated-containerruntime", pool.Name)
308			latestFinalizerIdx := -1
309			maxFinalizerSuffix := -1
310			for i, f := range finalizers {
311				// skip the finalizer:
312				// the finalizer is not a machineconfig
313				// the finalizer is not generated by containerruntimeconfig controller of this pool
314				if _, err := client.MachineconfigurationV1().MachineConfigs().Get(context.TODO(), f, metav1.GetOptions{}); err != nil {
315					klog.Infof("skipping error: %v", fmt.Errorf("containerruntimeconfig %s has invalid finalizer: %s", cfg.Name, f))
316					continue
317				}
318				if !strings.HasPrefix(f, containerRuntimeMCPrefix) {
319					continue
320				}
321				arr := strings.Split(f, "-")
322				suffix, err := strconv.Atoi(arr[len(arr)-1])
323				// if the finalizer does not end with a number, make sure it is in the format 99-<poolname>-generated-containerruntime
324				// otherwise, the ctrcfg contains invalid finalizer, do not generate managedKey from finalizers
325				if err != nil {
326					key, err := ctrlcommon.GetManagedKey(pool, nil, managedContainerRuntimeConfigKeyPrefix, "containerruntime", getManagedKeyCtrCfgDeprecated(pool))
327					if err != nil {
328						klog.Infof("skipping error: %v", fmt.Errorf("error generating managedKey for suffix %s: %w", key, err))
329						continue
330					}
331					if f != key {
332						klog.Infof("skipping error: %v", fmt.Errorf("finalizer format does not match the managedKubeletConfigKey: %s, want: %s", f, key))
333						continue
334					}
335					// if the suffix is not a number, f is 99-<poolname>-generated-containerruntime
336					suffix = 0
337				}
338				if suffix > maxFinalizerSuffix {
339					maxFinalizerSuffix = suffix
340					latestFinalizerIdx = i
341				}
342			}
343	
344			if latestFinalizerIdx != -1 {
345				klog.Infof("return containerruntimeconfig managedKey from finalizers %s", finalizers[latestFinalizerIdx])
346				return finalizers[latestFinalizerIdx], nil
347			}
348			klog.Infof("skipping error generating managedKey for existing containerruntimeconfig %s from finalizers", cfg.Name)
349		}
350		suffixNum := 0
351		// Go through the list of ctrcfg objects created and get the max suffix value currently created
352		for _, item := range ctrcfgList {
353			val, ok := item.GetAnnotations()[ctrlcommon.MCNameSuffixAnnotationKey]
354			if ok && val != "" {
355				// Convert the suffix value to int so we can look through the list and grab the max suffix created so far
356				intVal, err := strconv.Atoi(val)
357				if err != nil {
358					return "", fmt.Errorf("error converting %s to int: %w", val, err)
359				}
360				if intVal > suffixNum {
361					suffixNum = intVal
362				}
363			}
364		}
365		// The max suffix value that we can go till with this logic is 9 - this means that a user can create up to 10 different ctrcfg CRs.
366		// However, if there is a ctrcfg-1 mapping to mc-1 and ctrcfg-2 mapping to mc-2 and the user deletes ctrcfg-1, it will delete mc-1 but
367		// then if the user creates a ctrcfg-new it will map to mc-3. This is what we want as the latest ctrcfg created should be higher in priority
368		// so that those changes can be rolled out to the nodes. But users will have to be mindful of how many ctrcfg CRs they create. Don't think
369		// anyone should ever have the need to create 10 when they can simply update an existing ctrcfg unless it is to apply to another pool.
370		if suffixNum+1 > ctrlcommon.MaxMCNameSuffix {
371			return "", fmt.Errorf("max number of supported ctrcfgs (10) has been reached. Please delete old ctrcfgs before retrying")
372		}
373		// Return the default MC name with the suffixNum+1 value appended to it
374		return fmt.Sprintf("99-%s-generated-containerruntime-%s", pool.Name, strconv.Itoa(suffixNum+1)), nil
375	}
