423	// updateStorageConfig decodes the data rendered from the template, merges the changes in and encodes it
424	// back into a TOML format. It returns the bytes of the encoded data.
425	// The additionalStorageEnabled flag controls whether additional layer/image store
426	// fields are processed. Callers must pass the feature gate state to ensure
427	// gated fields are not written when the feature is disabled.
428	func updateStorageConfig(data []byte, internal *mcfgv1.ContainerRuntimeConfiguration, additionalStorageEnabled bool) ([]byte, error) {
429		tomlConf := new(tomlConfigStorage)
430		if _, err := toml.NewDecoder(bytes.NewBuffer(data)).Decode(tomlConf); err != nil {
431			return nil, fmt.Errorf("error decoding crio config: %w", err)
432		}
433	
434		if internal.OverlaySize != nil {
435			if internal.OverlaySize.Value() < 0 {
436				return nil, fmt.Errorf("invalid overlaySize config %q: the overlaySize should be larger than 0", internal.OverlaySize.String())
437			}
438	
439			if internal.OverlaySize.Value() != 0 {
440				tomlConf.Storage.Options.Size = internal.OverlaySize.String()
441			}
442		}
443	
444		if additionalStorageEnabled && len(internal.AdditionalLayerStores) > 0 {
445			paths := make([]string, 0, len(internal.AdditionalLayerStores))
446			for _, store := range internal.AdditionalLayerStores {
447				path := string(store.Path)
448				// containers/storage requires :ref for reference-based layer resolution
449				if !strings.HasSuffix(path, ":ref") {
450					path += ":ref"
451				}
452				paths = append(paths, path)
453			}
454			tomlConf.Storage.Options.AdditionalLayerStores = paths
455		}
456	
457		if additionalStorageEnabled && len(internal.AdditionalImageStores) > 0 {
458			paths := make([]string, 0, len(internal.AdditionalImageStores))
459			for _, store := range internal.AdditionalImageStores {
460				paths = append(paths, string(store.Path))
461			}
462			tomlConf.Storage.Options.AdditionalImageStores = paths
463		}
464	
465		var newData bytes.Buffer
466		encoder := toml.NewEncoder(&newData)
467		if err := encoder.Encode(*tomlConf); err != nil {
468			return nil, err
469		}
470	
471		return newData.Bytes(), nil
472	}
