484	// createCRIODropinFiles gets the data from the CRD and creates the respective drop in file in /etc/crio/crio.conf.d
485	// We create different drop-in files for each CRI-O field that can be changed by the ctrcfg CR
486	// this ensures that we don't have to rely on hard coded defaults that might cause problems
487	// in future if something in cri-o or the templates used by the MCO changes.
488	// The additionalStorageEnabled flag controls whether additional artifact store
489	// fields are processed. Callers must pass the feature gate state to ensure
490	// gated fields are not written when the feature is disabled.
491	func createCRIODropinFiles(cfg *mcfgv1.ContainerRuntimeConfig, additionalStorageEnabled bool) []generatedConfigFile {
492		var (
493			generatedConfigFileList []generatedConfigFile
494			err                     error
495		)
496		ctrcfg := cfg.Spec.ContainerRuntimeConfig
497		if ctrcfg.LogLevel != "" {
498			tomlConf := tomlConfigCRIOLogLevel{}
499			tomlConf.Crio.Runtime.LogLevel = ctrcfg.LogLevel
500			generatedConfigFileList, err = addTOMLgeneratedConfigFile(generatedConfigFileList, CRIODropInFilePathLogLevel, tomlConf)
501			if err != nil {
502				klog.V(2).Infof("error updating user changes for log-level to crio.conf.d: %v", err)
503			}
504		}
505		if ctrcfg.PidsLimit != nil {
506			tomlConf := tomlConfigCRIOPidsLimit{}
507			tomlConf.Crio.Runtime.PidsLimit = *ctrcfg.PidsLimit
508			generatedConfigFileList, err = addTOMLgeneratedConfigFile(generatedConfigFileList, crioDropInFilePathPidsLimit, tomlConf)
509			if err != nil {
510				klog.V(2).Infof("error updating user changes for pids-limit to crio.conf.d: %v", err)
511			}
512		}
513		if ctrcfg.LogSizeMax != nil && ctrcfg.LogSizeMax.Value() != 0 {
514			tomlConf := tomlConfigCRIOLogSizeMax{}
515			tomlConf.Crio.Runtime.LogSizeMax = ctrcfg.LogSizeMax.Value()
516			generatedConfigFileList, err = addTOMLgeneratedConfigFile(generatedConfigFileList, crioDropInFilePathLogSizeMax, tomlConf)
517			if err != nil {
518				klog.V(2).Infof("error updating user changes for log-size-max to crio.conf.d: %v", err)
519			}
520		}
521		if ctrcfg.DefaultRuntime != mcfgv1.ContainerRuntimeDefaultRuntimeEmpty {
522			tomlConf := tomlConfigCRIODefaultRuntime{}
523			tomlConf.Crio.Runtime.DefaultRuntime = string(ctrcfg.DefaultRuntime)
524			generatedConfigFileList, err = addTOMLgeneratedConfigFile(generatedConfigFileList, CRIODropInFilePathDefaultRuntime, tomlConf)
525			if err != nil {
526				klog.V(2).Infof("error updating user changes for default-runtime to crio.conf.d: %v", err)
527			}
528		}
529		if additionalStorageEnabled && len(ctrcfg.AdditionalArtifactStores) > 0 {
530			tomlConf := tomlConfigCRIOAdditionalArtifactStores{}
531			paths := make([]string, 0, len(ctrcfg.AdditionalArtifactStores))
532			for _, store := range ctrcfg.AdditionalArtifactStores {
533				paths = append(paths, string(store.Path))
534			}
535			tomlConf.Crio.Runtime.AdditionalArtifactStores = paths
536			generatedConfigFileList, err = addTOMLgeneratedConfigFile(generatedConfigFileList, crioDropInFilePathAdditionalArtifactStores, tomlConf)
537			if err != nil {
538				klog.V(2).Infof("error updating user changes for additional-artifact-stores to crio.conf.d: %v", err)
539			}
540		}
541		return generatedConfigFileList
542	}
