584	// updatePolicyJSON decodes the data rendered from the template, merges the changes in and encodes it
585	// back into a JSON format. It returns the bytes of the encoded data
586	// It also returns an error if both allowed and blocked registries are set
587	// WARNING: This can not safely edit policy files with arbitrary complexity, especially files which include signedBy
588	// requirements. It expects the input policy to be generated by templates in this project.
589	func updatePolicyJSON(data []byte, internalBlocked, internalAllowed []string, releaseImage string, clusterScopePolicies map[string]signature.PolicyRequirements) ([]byte, error) {
590		if len(internalAllowed) != 0 && len(internalBlocked) != 0 {
591			payloadRepo, err := getPayloadRepo(releaseImage)
592			if err != nil {
593				return nil, err
594			}
595			// If the internalAllowed list only has one entry and it matches the payload repo, that is fine and we can continue.
596			// Otherwise throw an error that the allowed and blocked lists are not allowed to be set at the same time.
597			if !(len(internalAllowed) == 1 && internalAllowed[0] == payloadRepo.Name()) {
598				return nil, fmt.Errorf("invalid images config: only one of AllowedRegistries or BlockedRegistries may be specified")
599			}
600		}
601	
602		if err := validateImagePolicyWithAllowedBlockedRegistries(clusterScopePolicies, nil, internalAllowed, internalBlocked); err != nil {
603			return nil, err
604		}
605		// Return original data if neither allowed or blocked registries or clusterimagepolicy are configured
606		// Note: this ensures that the genetateNamespacedPolicyJSONs can inherite the cluster wide template policy.json, the controller does not call this function till
607		// allowed or blocked registries or clusterimagepolicy or imagepolicy are configured
608		if internalAllowed == nil && internalBlocked == nil && len(clusterScopePolicies) == 0 {
609			return data, nil
610		}
611	
612		if err := validateRegistriesConfScopes([]string{}, internalBlocked, internalAllowed, nil, nil, nil); err != nil {
613			return nil, err
614		}
615	
616		policyObj := &signature.Policy{}
617		decoder := json.NewDecoder(bytes.NewBuffer(data))
618		err := decoder.Decode(policyObj)
619		if err != nil {
620			return nil, fmt.Errorf("error decoding policy json: %w", err)
621		}
622		transportScopes := make(signature.PolicyTransportScopes)
623		if len(internalAllowed) > 0 {
624			policyObj.Default = signature.PolicyRequirements{
625				signature.NewPRReject(),
626			}
627			for _, reg := range internalAllowed {
628				if clusterScopePolicies[reg] != nil {
629					// do not set "insecureAcceptAnything" for the reg if this allowed reg is set in the clusterimagepolicy
630					continue
631				}
632				transportScopes[reg] = signature.PolicyRequirements{
633					signature.NewPRInsecureAcceptAnything(),
634				}
635			}
636		}
637		if len(internalBlocked) > 0 {
638			policyObj.Default = signature.PolicyRequirements{
639				signature.NewPRInsecureAcceptAnything(),
640			}
641			for _, reg := range internalBlocked {
642				transportScopes[reg] = signature.PolicyRequirements{
643					signature.NewPRReject(),
644				}
645			}
646		}
647	
648		for scope, requirement := range clusterScopePolicies {
649			transportScopes[scope] = append(transportScopes[scope], requirement...)
650		}
651	
652		if len(transportScopes) > 0 {
653			policyObj.Transports["docker"] = transportScopes
654			// The “atomic” policy is the same as the “docker” policy, but “atomic” does not support three or more
655			// scope segments, so filter those scopes out.
656			policyObj.Transports["atomic"] = make(signature.PolicyTransportScopes)
657			for reg, config := range transportScopes {
658				if strings.Count(reg, "/") >= 3 {
659					continue
660				}
661				policyObj.Transports["atomic"][reg] = config
662			}
663		}
664	
665		policyJSON, err := json.MarshalIndent(policyObj, "", "  ")
666		if err != nil {
667			return nil, err
668		}
669		return policyJSON, nil
670	}
