672	// validateUserContainerRuntimeConfig ensures that the values set by the user are valid
673	func validateUserContainerRuntimeConfig(cfg *mcfgv1.ContainerRuntimeConfig) error {
674		if cfg.Spec.ContainerRuntimeConfig == nil {
675			return nil
676		}
677		ctrcfgValues := reflect.ValueOf(*cfg.Spec.ContainerRuntimeConfig)
678		if !ctrcfgValues.IsValid() {
679			return fmt.Errorf("containerRuntimeConfig is not valid")
680		}
681	
682		ctrcfg := cfg.Spec.ContainerRuntimeConfig
683		if ctrcfg.PidsLimit != nil && *ctrcfg.PidsLimit != 0 && *ctrcfg.PidsLimit < minPidsLimit {
684			return fmt.Errorf("invalid PidsLimit %v", *ctrcfg.PidsLimit)
685		}
686	
687		if ctrcfg.LogSizeMax != nil && ctrcfg.LogSizeMax.Value() > 0 && ctrcfg.LogSizeMax.Value() <= minLogSize {
688			return fmt.Errorf("invalid LogSizeMax %q, cannot be less than 8kB", ctrcfg.LogSizeMax.String())
689		}
690	
691		if ctrcfg.OverlaySize != nil && ctrcfg.OverlaySize.Value() < 0 {
692			return fmt.Errorf("invalid overlaySize %q, cannot be less than 0", ctrcfg.OverlaySize.String())
693		}
694	
695		if ctrcfg.LogLevel != "" {
696			validLogLevels := map[string]bool{
697				"error": true,
698				"fatal": true,
699				"panic": true,
700				"warn":  true,
701				"info":  true,
702				"debug": true,
703				"trace": true,
704			}
705			if !validLogLevels[ctrcfg.LogLevel] {
706				return fmt.Errorf("invalid LogLevel %q, must be one of error, fatal, panic, warn, info, debug, or trace", ctrcfg.LogLevel)
707			}
708		}
709	
710		switch ctrcfg.DefaultRuntime {
711		case mcfgv1.ContainerRuntimeDefaultRuntimeEmpty, mcfgv1.ContainerRuntimeDefaultRuntimeRunc, mcfgv1.ContainerRuntimeDefaultRuntimeCrun:
712		default:
713			return fmt.Errorf("invalid DefaultRuntime %q, must be one of %s, %s", ctrcfg.DefaultRuntime, mcfgv1.ContainerRuntimeDefaultRuntimeCrun, mcfgv1.ContainerRuntimeDefaultRuntimeRunc)
714		}
715	
716		// Validate store paths regardless of feature gate state. This catches
717		// invalid configuration early so that enabling the gate later does not
718		// surface errors that were silently present in the CR.
719		var errs []error
720		for _, store := range ctrcfg.AdditionalLayerStores {
721			if err := validateStorePath(store.Path, "AdditionalLayerStores"); err != nil {
722				errs = append(errs, err)
723			}
724		}
725		for _, store := range ctrcfg.AdditionalImageStores {
726			if err := validateStorePath(store.Path, "AdditionalImageStores"); err != nil {
727				errs = append(errs, err)
728			}
729		}
730		for _, store := range ctrcfg.AdditionalArtifactStores {
731			if err := validateStorePath(store.Path, "AdditionalArtifactStores"); err != nil {
732				errs = append(errs, err)
733			}
734		}
735	
736		return errors.Join(errs...)
737	}
738	
739	// storePathRegexp matches the CRD CEL rule: ^/[a-zA-Z0-9/._-]+$
740	var storePathRegexp = regexp.MustCompile(`^/[a-zA-Z0-9/._-]+$`)
741	
742	// validateStorePath validates that a storage path is absolute, only contains
743	// allowed characters (a-z, A-Z, 0-9, '/', '.', '_', '-'), and does not
744	// contain consecutive forward slashes. This mirrors the CRD-level CEL
745	// validation so that invalid config is caught early.
746	func validateStorePath(p mcfgv1.StorePath, field string) error {
747		path := string(p)
748		if path == "" {
749			return fmt.Errorf("invalid %s: path must not be empty", field)
750		}
751		if !storePathRegexp.MatchString(path) {
752			return fmt.Errorf("invalid %s path %q: must be an absolute path containing only alphanumeric characters, '/', '.', '_', and '-'", field, path)
753		}
754		if strings.Contains(path, "//") {
755			return fmt.Errorf("invalid %s path %q: must not contain consecutive forward slashes", field, path)
756		}
757		return nil
758	}
759	
760	// getValidBlockedRegistries gets the blocked registries in the image spec and validates that the user is not adding
761	// the registry being used by the payload to the list of blocked registries.
762	// If the user is, we drop that registry and continue with syncing the registries.conf with the other registry options
763	// This returns the blocked list for registries.conf and policy.json separately as well as the allowed list for policy.json
764	func getValidBlockedAndAllowedRegistries(releaseImage string, imgSpec *apicfgv1.ImageSpec, icspRules []*apioperatorsv1alpha1.ImageContentSourcePolicy, idmsRules []*apicfgv1.ImageDigestMirrorSet) (registriesBlocked, policyBlocked, allowed []string, retErr error) {
765		if imgSpec == nil {
766			return nil, nil, nil, nil
767		}
768	
769		for _, icsp := range icspRules {
770			idmsRules = append(idmsRules, convertICSPToIDMS(icsp))
771		}
772	
773		var blockErr []string
774	
775		// Get the repository being used by the payload from the releaseImage
776		ref, err := getPayloadRepo(releaseImage)
777		if err != nil {
778			return nil, nil, nil, errParsingReference
779		}
780		payloadRepo := ref.Name()
781		for _, reg := range imgSpec.RegistrySources.BlockedRegistries {
782			// if there is a match, return all the blocked registries except those that matched and return an error as well
783			if runtimeutils.ScopeIsNestedInsideScope(payloadRepo, reg) {
784				// If the payload registry doesn't have mirror rules configured for it, then don't add it to the blocked registries list
785				// Note that we care only about digest mirrors (and not ImageTagMirrorSet) because the OpenShift release payload only uses digest references.
786				hasMirror, err := payloadRepoHasUnblockedMirror(ref, idmsRules, imgSpec)
787				if err != nil {
788					return nil, nil, nil, err
789				}
790				if !hasMirror {
791					blockErr = append(blockErr, reg)
792					continue
793				}
794				// Log a warning that we are adding the payload registries to the blocked registries list as there are mirror rules for it
795				klog.Warningf("%q matches the payload repository, but will add it to the list of blocked registries as there are mirror rules configured for it", reg)
796				// Intentionally do NOT add reg to policyBlocked, to allow using payloadRepo (physically accessing the mirrors)
797				// In the future, this will be user-controlled via https://github.com/openshift/api/blob/1a6fa2913810101176a1d776f899fc4781b3fa50/config/v1/types_image_digest_mirror_set.go#L74
798				registriesBlocked = append(registriesBlocked, reg)
799				// If reg is not exactly the same as payloadRepo, then add it to the policy blocked list as it may be another repo in the payload registry
800				if payloadRepo != reg {
801					policyBlocked = append(policyBlocked, reg)
802				}
803				// Always add the payloadRepo to policy allowed so we can resolve for mirrors for it
804				allowed = append(allowed, payloadRepo)
805				continue
806			}
807			// Was not a match to the registry being used by the payload, so add to valid blocked registries
808			registriesBlocked = append(registriesBlocked, reg)
809			policyBlocked = append(policyBlocked, reg)
810		}
811		if len(blockErr) > 0 {
812			retErr = fmt.Errorf("error adding %q to blocked registries, cannot block the repository being used by the payload", blockErr)
813		}
814		allowed = append(allowed, imgSpec.RegistrySources.AllowedRegistries...)
815		return registriesBlocked, policyBlocked, allowed, retErr
816	}
817	
818	// payloadRepoHasUnblockedMirror returns true if the payload registry has mirror rules configured for it
819	func payloadRepoHasUnblockedMirror(payloadRepo reference.Named, idmsRules []*apicfgv1.ImageDigestMirrorSet, imgSpec *apicfgv1.ImageSpec) (bool, error) {
820		// Create a temp registries.conf file with all the registry inputs given
821		tmpFile, err := createTempRegistriesFile(idmsRules, imgSpec)
822		if err != nil {
823			return false, err
824		}
825		defer os.Remove(tmpFile.Name())
826	
827		// Go through the mirror rules configured and check if a source matches the payload registry
828		// Get the possible pull sources for the payload repo using the temp registries.conf file created above
829		r, err := sysregistriesv2.FindRegistry(&types.SystemContext{SystemRegistriesConfPath: tmpFile.Name()}, payloadRepo.Name())
830		if err != nil {
831			return false, err
832		}
833		sources, err := r.PullSourcesFromReference(payloadRepo)
834		if err != nil {
835			return false, err
836		}
837	
838		// Go through the list of pull sources and check that at least one of the payload references is not blocked
839		for _, s := range sources {
840			isUsable := true
841			for _, blockReg := range imgSpec.RegistrySources.BlockedRegistries {
842				if runtimeutils.ScopeIsNestedInsideScope(s.Reference.Name(), blockReg) {
843					isUsable = false
844				}
845			}
846			if isUsable {
847				return true, nil
848			}
849		}
850		return false, nil
851	}
