853	// createTempRegistriesFile creates a temporary registries config file to be used in determining the valid blocked and allowed registries
854	func createTempRegistriesFile(idmsRules []*apicfgv1.ImageDigestMirrorSet, imgSpec *apicfgv1.ImageSpec) (*os.File, error) {
855		tomlConf := sysregistriesv2.V2RegistriesConf{}
856		if err := registries.EditRegistriesConfig(&tomlConf, imgSpec.RegistrySources.InsecureRegistries, imgSpec.RegistrySources.BlockedRegistries, nil, idmsRules, nil); err != nil {
857			return nil, err
858		}
859		var newData bytes.Buffer
860		encoder := toml.NewEncoder(&newData)
861		if err := encoder.Encode(tomlConf); err != nil {
862			return nil, err
863		}
864		tmpFile, err := os.CreateTemp("", "regtemp")
865		if err != nil {
866			return nil, err
867		}
868		defer tmpFile.Close()
869	
870		_, err = tmpFile.Write(newData.Bytes())
871		if err != nil {
872			return nil, err
873		}
874	
875		return tmpFile, nil
876	}
