887	func validateRegistriesConfScopes(insecure, blocked, allowed []string, icspRules []*apioperatorsv1alpha1.ImageContentSourcePolicy, idmsRules []*apicfgv1.ImageDigestMirrorSet, itmsRules []*apicfgv1.ImageTagMirrorSet) error {
888		for _, scope := range insecure {
889			if !registries.IsValidRegistriesConfScope(scope) {
890				return fmt.Errorf("invalid entry for insecure registries %q", scope)
891			}
892		}
893	
894		for _, scope := range blocked {
895			if !registries.IsValidRegistriesConfScope(scope) {
896				return fmt.Errorf("invalid entry for blocked registries %q", scope)
897			}
898		}
899	
900		for _, scope := range allowed {
901			if !registries.IsValidRegistriesConfScope(scope) {
902				return fmt.Errorf("invalid entry for allowed registries %q", scope)
903			}
904		}
905	
906		sourcePolicy := map[string]apicfgv1.MirrorSourcePolicy{}
907		validateMirrors := func(source string, mirrors []apicfgv1.ImageMirror, policy apicfgv1.MirrorSourcePolicy) error {
908			if !sourceRegex.MatchString(source) {
909				return fmt.Errorf("invalid format for source %q", source)
910			}
911			if policy == "" {
912				policy = apicfgv1.AllowContactingSource
913			}
914			if p, ok := sourcePolicy[source]; ok {
915				if policy != p {
916					return fmt.Errorf("conflicting mirrorSourcePolicy is set for the same source %q in imagedigestmirrorsets, imagetagmirrorsets, or imagecontentsourcepolicies", source)
917				}
918			} else {
919				sourcePolicy[source] = policy
920			}
921	
922			for _, mirror := range mirrors {
923				if !mirrorRegex.MatchString(string(mirror)) {
924					return fmt.Errorf("invalid format for mirror %q", mirror)
925				}
926				if policy == apicfgv1.NeverContactSource && string(mirror) == source {
927					return fmt.Errorf("cannot set mirrorSourcePolicy: NeverContactSource if the source %q is one of the mirrors", source)
928				}
929			}
930			return nil
931		}
932	
933		for _, icsp := range icspRules {
934			idmsRules = append(idmsRules, convertICSPToIDMS(icsp))
935		}
936	
937		for _, idms := range idmsRules {
938			for _, mirrorSet := range idms.Spec.ImageDigestMirrors {
939				if err := validateMirrors(mirrorSet.Source, mirrorSet.Mirrors, mirrorSet.MirrorSourcePolicy); err != nil {
940					return err
941				}
942			}
943		}
944	
945		for _, itms := range itmsRules {
946			for _, mirrorSet := range itms.Spec.ImageTagMirrors {
947				if err := validateMirrors(mirrorSet.Source, mirrorSet.Mirrors, mirrorSet.MirrorSourcePolicy); err != nil {
948					return err
949				}
950			}
951		}
952		return nil
953	}
