955	// convertICSPToIDMS converts ImageContentSourcePolicy to ImageDigestMirrorSet struct
956	func convertICSPToIDMS(icsp *apioperatorsv1alpha1.ImageContentSourcePolicy) *apicfgv1.ImageDigestMirrorSet {
957		var imageDigestMirrors []apicfgv1.ImageDigestMirrors
958	
959		for _, mirrorSet := range icsp.Spec.RepositoryDigestMirrors {
960			var mirrors []apicfgv1.ImageMirror
961			for _, mirror := range mirrorSet.Mirrors {
962				mirrors = append(mirrors, apicfgv1.ImageMirror(mirror))
963			}
964			imageDigestMirror := apicfgv1.ImageDigestMirrors{
965				Source:  mirrorSet.Source,
966				Mirrors: mirrors,
967			}
968			imageDigestMirrors = append(imageDigestMirrors, imageDigestMirror)
969		}
970		return &apicfgv1.ImageDigestMirrorSet{
971			Spec: apicfgv1.ImageDigestMirrorSetSpec{
972				ImageDigestMirrors: imageDigestMirrors,
973			},
974		}
975	}
