300	// ConvertRawExtIgnitionToV3_5 ensures that the Ignition config in
301	// the RawExtension is spec v3.5, or translates to it.
302	func ConvertRawExtIgnitionToV3_5(inRawExtIgn *runtime.RawExtension) (runtime.RawExtension, error) {
303		// Parse the raw extension to the MCO's current internal ignition version
304		ignCfgV3, err := IgnParseWrapper(inRawExtIgn.Raw)
305		if err != nil {
306			return runtime.RawExtension{}, err
307		}
308	
309		// TODO(jkyros): we used to only re-marshal this if it was the wrong version, now we're
310		// re-marshaling every time
311		outIgnV3, err := json.Marshal(ignCfgV3)
312		if err != nil {
313			return runtime.RawExtension{}, fmt.Errorf("failed to marshal converted config: %w", err)
314		}
315	
316		outRawExt := runtime.RawExtension{}
317		outRawExt.Raw = outIgnV3
318	
319		return outRawExt, nil
320	}
