322	// ConvertRawExtIgnitionToVersion takes the Ignition config in the
323	// RawExtension and translates it to the requested targetVersion.
324	func ConvertRawExtIgnitionToVersion(inRawExtIgn *runtime.RawExtension, targetVersion semver.Version) (runtime.RawExtension, error) {
325		rawExt, err := ConvertRawExtIgnitionToV3_5(inRawExtIgn)
326		if err != nil {
327			return runtime.RawExtension{}, err
328		}
329	
330		ignCfgV3, rptV3, errV3 := ign3.Parse(rawExt.Raw)
331		if errV3 != nil || rptV3.IsFatal() {
332			return runtime.RawExtension{}, fmt.Errorf("parsing Ignition config failed with error: %w\nReport: %v", errV3, rptV3)
333		}
334	
335		conversion, err := ignitionConverter.Convert(ignCfgV3, ign3types.MaxVersion, targetVersion)
336		if err != nil {
337			return runtime.RawExtension{}, err
338		}
339	
340		out, err := json.Marshal(conversion)
341		if err != nil {
342			return runtime.RawExtension{}, fmt.Errorf("failed to marshal converted config: %w", err)
343		}
344	
345		return runtime.RawExtension{Raw: out}, nil
346	}
