470	// ValidateMachineConfigSize checks if the MachineConfig size exceeds etcd limits.
471	// etcd has a default request size limit of 1.5MB. This function validates that the
472	// rendered MachineConfig does not exceed this limit to prevent "etcdserver: request
473	// is too large" errors.
474	func ValidateMachineConfigSize(mc *mcfgv1.MachineConfig) error {
475		// Marshal the MachineConfig to JSON to get its actual size as it will be sent to etcd
476		data, err := json.Marshal(mc)
477		if err != nil {
478			return fmt.Errorf("failed to marshal MachineConfig: %w", err)
479		}
480	
481		size := len(data)
482	
483		// Check if size exceeds the limit
484		if size > MaxMachineConfigSize {
485			return fmt.Errorf("rendered MachineConfig %s is too large (%d bytes, max %d bytes). "+
486				"This will exceed etcd's size limit. Consider reducing the number or size of MachineConfigs, "+
487				"particularly large registry mirror configurations (ImageDigestMirrorSet/ImageContentSourcePolicy)",
488				mc.Name, size, MaxMachineConfigSize)
489		}
490	
491		// Log size information at debug level
492		percentUsed := float64(size) / float64(MaxMachineConfigSize) * 100
493		klog.V(4).Infof("MachineConfig %s size: %d bytes (%.2f%% of %d byte limit)",
494			mc.Name, size, percentUsed, MaxMachineConfigSize)
495	
496		// Warn if approaching the limit (> 80%)
497		warningThreshold := (MaxMachineConfigSize * 4) / 5
498		if size > warningThreshold {
499			klog.Warningf("MachineConfig %s is approaching size limit: %d bytes (%.2f%% of %d byte limit). "+
500				"Consider reducing MachineConfig size to avoid hitting the limit.",
501				mc.Name, size, percentUsed, MaxMachineConfigSize)
502		}
503	
504		return nil
505	}
