512	func validateExtensions(exts []string) error {
513		supportedExtensions := SupportedExtensions()
514		invalidExts := []string{}
515		for _, ext := range exts {
516			if _, ok := supportedExtensions[ext]; !ok {
517				invalidExts = append(invalidExts, ext)
518			}
519		}
520		if len(invalidExts) != 0 {
521			return fmt.Errorf("invalid extensions found: %v", invalidExts)
522		}
523		return nil
524	}
