576	// IgnParseWrapper parses rawIgn for both V2 and V3 ignition configs and returns
577	// a V2 or V3 Config or an error. This wrapper is necessary since V2 and V3 use different parsers.
578	func IgnParseWrapper(rawIgn []byte) (interface{}, error) {
579		// ParseCompatibleVersion will parse any config <= N to version N
580		ignCfgV3, rptV3, errV3 := ign3.ParseCompatibleVersion(rawIgn)
581		if errV3 == nil && !rptV3.IsFatal() {
582			return ignCfgV3, nil
583		}
584	
585		// ParseCompatibleVersion differentiates between ErrUnknownVersion ("I know what it is and we don't support it") and
586		// ErrInvalidVersion ("I can't parse it to find out what it is"), but our old 3.2 logic didn't, so this is here to make sure
587		// our error message for invalid version is still helpful.
588		if errV3.Error() == ign3error.ErrInvalidVersion.Error() {
589			versions := strings.TrimSuffix(strings.Join(IgnitionConverterSingleton().GetSupportedMinorVersions(), ","), ",")
590			return ign3types.Config{}, fmt.Errorf("parsing Ignition config failed: invalid version. Supported spec versions: %s", versions)
591		}
592	
593		if errV3.Error() == ign3error.ErrUnknownVersion.Error() {
594			ignCfgV2, rptV2, errV2 := ign2.Parse(rawIgn)
595			if errV2 == nil && !rptV2.IsFatal() {
596				return ignCfgV2, nil
597			}
598	
599			// If the error is still UnknownVersion it's not a 3.3/3.2/3.1/3.0 or 2.x config, thus unsupported
600			if errV2.Error() == ign2error.ErrUnknownVersion.Error() {
601				versions := strings.TrimSuffix(strings.Join(IgnitionConverterSingleton().GetSupportedMinorVersions(), ","), ",")
602				return ign3types.Config{}, fmt.Errorf("parsing Ignition config failed: unknown version. Supported spec versions: %s", versions)
603			}
604			return ign3types.Config{}, fmt.Errorf("parsing Ignition spec v2 failed with error: %v\nReport: %v", errV2, rptV2)
605		}
606	
607		return ign3types.Config{}, fmt.Errorf("parsing Ignition config spec v3 failed with error: %v\nReport: %v", errV3, rptV3)
608	}
609	
610	// ParseAndConvertConfig parses rawIgn for both V2 and V3 ignition configs and returns
611	// a V3 or an error.
612	func ParseAndConvertConfig(rawIgn []byte) (ign3types.Config, error) {
613		ignconfigi, err := IgnParseWrapper(rawIgn)
614		if err != nil {
615			return ign3types.Config{}, fmt.Errorf("failed to parse Ignition config: %w", err)
616		}
617	
618		switch typedConfig := ignconfigi.(type) {
619		case ign3types.Config:
620			return ignconfigi.(ign3types.Config), nil
621		case ign2types.Config:
622			ignconfv2, err := removeIgnDuplicateFilesUnitsUsers(ignconfigi.(ign2types.Config))
623			if err != nil {
624				return ign3types.Config{}, err
625			}
626			convertedIgnV3, err := ignitionConverter.Convert(ignconfv2, *semver.New(ignconfv2.Ignition.Version), ign3types.MaxVersion)
627			if err != nil {
628				return ign3types.Config{}, fmt.Errorf("failed to convert Ignition config spec v2 to v3: %w", err)
629			}
630			return convertedIgnV3.(ign3types.Config), nil
631		default:
632			return ign3types.Config{}, fmt.Errorf("unexpected type for ignition config: %v", typedConfig)
633		}
634	}
