636	// Internal error used for base64-decoding and gunzipping Ignition configs
637	var errConfigNotGzipped = fmt.Errorf("ignition config not gzipped")
638	
639	// Decode, decompress, and deserialize an Ignition config file.
640	func ParseAndConvertGzippedConfig(rawIgn []byte) (ign3types.Config, error) {
641		// Try to decode and decompress our payload
642		out, err := DecodeAndDecompressPayload(bytes.NewReader(rawIgn))
643		if err == nil {
644			// Our payload was decoded and decompressed, so parse it as Ignition.
645			klog.V(2).Info("ignition config was base64-decoded and gunzipped successfully")
646			return ParseAndConvertConfig(out)
647		}
648	
649		// Our Ignition config is not base64-encoded, which means it might only be gzipped:
650		// e.g.: $ gzip -9 ign_config.json
651		var base64Err base64.CorruptInputError
652		if errors.As(err, &base64Err) {
653			klog.V(2).Info("ignition config was not base64 encoded, trying to gunzip ignition config")
654			out, err = decompressPayload(bytes.NewReader(rawIgn))
655			if err == nil {
656				// We were able to decompress our payload, so let's try parsing it
657				klog.V(2).Info("ignition config was gunzipped successfully")
658				return ParseAndConvertConfig(out)
659			}
660		}
661	
662		// Our Ignition config is not gzipped, so let's try to serialize the raw Ignition directly.
663		if errors.Is(err, errConfigNotGzipped) {
664			klog.V(2).Info("ignition config was not gzipped")
665			return ParseAndConvertConfig(rawIgn)
666		}
667	
668		return ign3types.Config{}, fmt.Errorf("unable to read ignition config: %w", err)
669	}
670	
671	// Attempts to base64-decode and/or decompresses a given byte array.
672	func DecodeAndDecompressPayload(r io.Reader) ([]byte, error) {
673		// Wrap the io.Reader in a base64 decoder (which implements io.Reader)
674		base64Dec := base64.NewDecoder(base64.StdEncoding, r)
675		out, err := decompressPayload(base64Dec)
676		if err == nil {
677			return out, nil
678		}
679	
680		return nil, fmt.Errorf("unable to decode and decompress payload: %w", err)
681	}
682	
683	// Checks if a given io.Reader contains known gzip headers and if so, gunzips
684	// the contents.
685	func decompressPayload(r io.Reader) ([]byte, error) {
686		// Wrap our io.Reader in a bufio.Reader. This allows us to peek ahead to
687		// determine if we have a valid gzip archive.
688		in := bufio.NewReader(r)
689		headerBytes, err := in.Peek(2)
690		if err != nil {
691			return nil, fmt.Errorf("could not peek: %w", err)
692		}
693	
694		// gzipped files have a header in the first two bytes which contain a magic
695		// number that indicate they are gzipped. We check if these magic numbers are
696		// present as a quick and easy way to determine if our payload is gzipped.
697		//
698		// See: https://cs.opensource.google/go/go/+/refs/tags/go1.19:src/compress/gzip/gunzip.go;l=20-21
699		if headerBytes[0] != 0x1f && headerBytes[1] != 0x8b {
700			return nil, errConfigNotGzipped
701		}
702	
703		gz, err := gzip.NewReader(in)
704		if err != nil {
705			return nil, fmt.Errorf("initialize gzip reader failed: %w", err)
706		}
707	
708		defer gz.Close()
709	
710		data, err := io.ReadAll(gz)
711		if err != nil {
712			return nil, fmt.Errorf("decompression failed: %w", err)
713		}
714	
715		return data, nil
716	}
