810	// TranspileCoreOSConfigToIgn transpiles Fedora CoreOS config to ignition
811	// internally it transpiles to Ign spec v3 config
812	func TranspileCoreOSConfigToIgn(files, units []string) (*ign3types.Config, error) {
813		overwrite := true
814		outConfig := ign3types.Config{}
815		// Convert data to Ignition resources
816		for _, contents := range files {
817			f := new(fcctbase.File)
818			if err := yaml.Unmarshal([]byte(contents), f); err != nil {
819				return nil, fmt.Errorf("failed to unmarshal %q into struct: %w", contents, err)
820			}
821			f.Overwrite = &overwrite
822	
823			// Add the file to the config
824			var ctCfg fcctbase.Config
825			ctCfg.Storage.Files = append(ctCfg.Storage.Files, *f)
826			ign30Config, tSet, err := ctCfg.ToIgn3_0()
827			if err != nil {
828				return nil, fmt.Errorf("failed to transpile config to Ignition config %w\nTranslation set: %v", err, tSet)
829			}
830			ign3Config, err := ignitionConverter.Convert(ign30Config, *semver.New(ign30Config.Ignition.Version), ign3types.MaxVersion)
831			if err != nil {
832				return nil, fmt.Errorf("failed to convert config from 3.0 to %v. %w", ign3types.MaxVersion, err)
833			}
834			outConfig = ign3.Merge(outConfig, ign3Config.(ign3types.Config))
835		}
836	
837		for _, contents := range units {
838			u := new(fcctbase.Unit)
839			if err := yaml.Unmarshal([]byte(contents), u); err != nil {
840				return nil, fmt.Errorf("failed to unmarshal systemd unit into struct: %w", err)
841			}
842	
843			// Add the unit to the config
844			var ctCfg fcctbase.Config
845			ctCfg.Systemd.Units = append(ctCfg.Systemd.Units, *u)
846			ign30Config, tSet, err := ctCfg.ToIgn3_0()
847			if err != nil {
848				return nil, fmt.Errorf("failed to transpile config to Ignition config %w\nTranslation set: %v", err, tSet)
849			}
850			ign3Config, err := ignitionConverter.Convert(ign30Config, *semver.New(ign30Config.Ignition.Version), ign3types.MaxVersion)
851			if err != nil {
852				return nil, fmt.Errorf("failed to convert config from 3.0 to %v. %w", ign3types.MaxVersion, err)
853			}
854			outConfig = ign3.Merge(outConfig, ign3Config.(ign3types.Config))
855		}
856	
857		return &outConfig, nil
858	}
