888	// GetManagedKey returns the managed key for sub-controllers, handling any migration needed
889	func GetManagedKey(pool *mcfgv1.MachineConfigPool, client mcfgclientset.Interface, prefix, suffix, deprecatedKey string) (string, error) {
890		managedKey := fmt.Sprintf("%s-%s-generated-%s", prefix, pool.Name, suffix)
891		// if we don't have a client, we're installing brand new, and we don't need to adjust for backward compatibility
892		if client == nil {
893			return managedKey, nil
894		}
895		if _, err := client.MachineconfigurationV1().MachineConfigs().Get(context.TODO(), managedKey, metav1.GetOptions{}); err == nil {
896			return managedKey, nil
897		}
898		old, err := client.MachineconfigurationV1().MachineConfigs().Get(context.TODO(), deprecatedKey, metav1.GetOptions{})
899		if err != nil && !kerr.IsNotFound(err) {
900			return "", fmt.Errorf("could not get MachineConfig %q: %w", deprecatedKey, err)
901		}
902		// this means no previous CR config were here, so we can start fresh
903		if kerr.IsNotFound(err) {
904			return managedKey, nil
905		}
906		// if we're here, we'll grab the old CR config, dupe it and patch its name
907		mc, err := MachineConfigFromRawIgnConfig(pool.Name, managedKey, old.Spec.Config.Raw)
908		if err != nil {
909			return "", err
910		}
911		_, err = client.MachineconfigurationV1().MachineConfigs().Create(context.TODO(), mc, metav1.CreateOptions{})
912		if err != nil {
913			return "", err
914		}
915		err = client.MachineconfigurationV1().MachineConfigs().Delete(context.TODO(), deprecatedKey, metav1.DeleteOptions{})
