919	// Ensures SSH keys are unique for a given Ign 2 PasswdUser
920	// See: https://bugzilla.redhat.com/show_bug.cgi?id=1934176
921	func dedupePasswdUserSSHKeys(passwdUser ign2types.PasswdUser) ign2types.PasswdUser {
922		// Map for checking for duplicates.
923		knownSSHKeys := map[ign2types.SSHAuthorizedKey]bool{}
924	
925		// Preserve ordering of SSH keys.
926		dedupedSSHKeys := []ign2types.SSHAuthorizedKey{}
927	
928		for _, sshKey := range passwdUser.SSHAuthorizedKeys {
929			if _, isKnown := knownSSHKeys[sshKey]; isKnown {
930				// We've seen this key before warn and move on.
931				klog.Warningf("duplicate SSH public key found: %s", sshKey)
932				continue
933			}
934	
935			// We haven't seen this key before, add it.
936			dedupedSSHKeys = append(dedupedSSHKeys, sshKey)
937			knownSSHKeys[sshKey] = true
938		}
939	
940		// Overwrite the keys with the deduped list.
941		passwdUser.SSHAuthorizedKeys = dedupedSSHKeys
942	
943		return passwdUser
944	}
