946	// CalculateConfigFileDiffs compares the files present in two ignition configurations and returns the list of files
947	// that are different between them
948	//
949	//nolint:dupl
950	func CalculateConfigFileDiffs(oldIgnConfig, newIgnConfig *ign3types.Config) []string {
951		// Go through the files and see what is new or different
952		oldFileSet := make(map[string]ign3types.File)
953		for _, f := range oldIgnConfig.Storage.Files {
954			oldFileSet[f.Path] = f
955		}
956		newFileSet := make(map[string]ign3types.File)
957		for _, f := range newIgnConfig.Storage.Files {
958			newFileSet[f.Path] = f
959		}
960		diffFileSet := []string{}
961	
962		// First check if any files were removed
963		for path := range oldFileSet {
964			_, ok := newFileSet[path]
965			if !ok {
966				diffFileSet = append(diffFileSet, path)
967			}
968		}
969	
970		// Now check if any files were added/changed
971		for path, newFile := range newFileSet {
972			oldFile, ok := oldFileSet[path]
973			if !ok {
974				diffFileSet = append(diffFileSet, path)
975			} else if !reflect.DeepEqual(oldFile, newFile) {
976				diffFileSet = append(diffFileSet, path)
977			}
978		}
979		return diffFileSet
980	}
