988	// GetChangedConfigUnitsByType compares the units present in two ignition configurations, one
989	// old config and the other new, a struct with units mapped to the type of change:
990	//   - New unit added: "Added"
991	//   - Unit previously existing removed: "Removed"
992	//   - Existing unit changed in some way: "Updated"
993	func GetChangedConfigUnitsByType(oldIgnConfig, newIgnConfig *ign3types.Config) (unitDiffs UnitDiff) {
994		diffUnit := UnitDiff{
995			Added:   []ign3types.Unit{},
996			Removed: []ign3types.Unit{},
997			Updated: []ign3types.Unit{},
998		}
999	
1000		// Get the sets of the old and new units from the ignition configurations
1001		oldUnitSet := make(map[string]ign3types.Unit)
1002		for _, u := range oldIgnConfig.Systemd.Units {
1003			oldUnitSet[u.Name] = u
1004		}
1005		newUnitSet := make(map[string]ign3types.Unit)
1006		for _, u := range newIgnConfig.Systemd.Units {
1007			newUnitSet[u.Name] = u
1008		}
1009	
1010		// First check if any units were removed
1011		for unit := range oldUnitSet {
1012			_, ok := newUnitSet[unit]
1013			if !ok {
1014				diffUnit.Removed = append(diffUnit.Removed, oldUnitSet[unit])
1015			}
1016		}
1017	
1018		// Now check if any units were added or updated
1019		for name, newUnit := range newUnitSet {
1020			oldUnit, ok := oldUnitSet[name]
1021			if !ok {
1022				diffUnit.Added = append(diffUnit.Added, newUnitSet[name])
1023			} else if !reflect.DeepEqual(oldUnit, newUnit) {
1024				diffUnit.Updated = append(diffUnit.Updated, newUnitSet[name])
1025			}
1026		}
1027		return diffUnit
