1143	// ioutil.ReadDir has been deprecated with os.ReadDir.
1144	// ioutil.ReadDir() used to return []fs.FileInfo but os.ReadDir() returns []fs.DirEntry.
1145	// Making it helper function so that we can reuse coversion of []fs.DirEntry into []fs.FileInfo
1146	// Implementation to fetch fileInfo is taken from https://pkg.go.dev/io/ioutil#ReadDir
1147	func ReadDir(path string) ([]fs.FileInfo, error) {
1148		entries, err := os.ReadDir(path)
1149		if err != nil {
1150			return nil, fmt.Errorf("failed to read dir %q: %w", path, err)
1151		}
1152		infos := make([]fs.FileInfo, 0, len(entries))
1153		for _, entry := range entries {
1154			info, err := entry.Info()
1155			if err != nil {
1156				return nil, fmt.Errorf("failed to fetch fileInfo of %q in %q: %w", entry.Name(), path, err)
1157			}
1158			infos = append(infos, info)
1159		}
1160		return infos, nil
1161	}
