1207	// isSubdirectory checks if targetPath is a subdirectory of dirPath.
1208	func IsSubdirectory(dirPath, targetPath string) bool {
1209		// Clean and add trailing separator to dirPath to ensure proper matching
1210		dirPath = filepath.Clean(dirPath) + string(filepath.Separator)
1211		targetPath = filepath.Clean(targetPath)
1212	
1213		// Check if targetPath has dirPath as its prefix
1214		return strings.HasPrefix(targetPath, dirPath)
1215	}
