1217	func FindClosestFilePolicyPathMatch(diffPath string, filePolicies []opv1.NodeDisruptionPolicyStatusFile) (bool, []opv1.NodeDisruptionPolicyStatusAction) {
1218		matchLength := 0
1219		matchFound := false
1220		matchActions := []opv1.NodeDisruptionPolicyStatusAction{}
1221	
1222		for _, filePolicy := range filePolicies {
1223			klog.V(4).Infof("comparing policy path %s to diff path %s", filePolicy.Path, diffPath)
1224			// Check if either of the following are true:
1225			// (i) if diffPath and filePolicy.Path are an exact match
1226			// (ii) if diffPath is a subdir of filePolicy.Path
1227			if (diffPath == filePolicy.Path) || IsSubdirectory(filePolicy.Path, diffPath) {
1228				// If a match was found, compare the length so the longest match is preserved
1229				if len(filePolicy.Path) > matchLength {
1230					matchFound = true
1231					matchLength = len(filePolicy.Path)
1232					matchActions = filePolicy.Actions
1233				}
1234			}
1235		}
1236		return matchFound, matchActions
1237	}
