229			if rawCfgIgn == nil {
230				continue
231			}
232	
233			// Get MachineConfig
234			managedKey, err := getManagedFeaturesKey(pool, nil)
235			if err != nil {
236				return nil, err
237			}
238	
239			ignConfig := ctrlcommon.NewIgnConfig()
240			mc, err := ctrlcommon.MachineConfigFromIgnConfig(role, managedKey, ignConfig)
241			if err != nil {
242				return nil, err
243			}
244	
245			mc.Spec.Config.Raw = rawCfgIgn
246			mc.ObjectMeta.Annotations = map[string]string{
247				ctrlcommon.GeneratedByControllerVersionAnnotationKey: version.Hash,
248			}
249	
250			machineConfigs = append(machineConfigs, mc)
251		}
252	
253		return machineConfigs, nil
254	}
