29	func (ctrl *Controller) processNextNodeConfigWorkItem() bool {
30		key, quit := ctrl.nodeConfigQueue.Get()
31		if quit {
32			return false
33		}
34		defer ctrl.nodeConfigQueue.Done(key)
35	
36		err := ctrl.syncNodeConfigHandler(key)
37		ctrl.handleNodeConfigErr(err, key)
38		return true
39	}
