41	func (ctrl *Controller) handleNodeConfigErr(err error, key string) {
42		if err == nil {
43			ctrl.nodeConfigQueue.Forget(key)
44			return
45		}
46	
47		if ctrl.nodeConfigQueue.NumRequeues(key) < maxRetries {
48			klog.V(4).Infof("Error syncing node configuration %v: %v", key, err)
49			ctrl.nodeConfigQueue.AddRateLimited(key)
50			return
51		}
52	
53		utilruntime.HandleError(err)
54		klog.V(2).Infof("Dropping node config %q out of the queue: %v", key, err)
55		ctrl.nodeConfigQueue.Forget(key)
56		ctrl.nodeConfigQueue.AddAfter(key, 1*time.Minute)
57	}
