59	// syncNodeConfigHandler syncs whenever there is a change on the nodes.config.openshift.io resource
60	// nodes.config.openshift.io object holds the cluster-wide information about the
61	// node specific features such as cgroup modes, workerlatencyprofiles, etc.
62	func (ctrl *Controller) syncNodeConfigHandler(key string) error {
63		startTime := time.Now()
64		klog.V(4).Infof("Started syncing nodeConfig handler %q (%v)", key, startTime)
65		defer func() {
66			klog.V(4).Infof("Finished syncing nodeConfig handler %q (%v)", key, time.Since(startTime))
67		}()
68	
69		// Fetch the Node
70		nodeConfig, err := getConfigNode(ctrl, key)
71		if err != nil {
72			err := fmt.Errorf("could not fetch Node: %w", err)
73			return err
74		}
75		if err := ctrl.cleanUpDuplicatedMC(managedNodeConfigKeyPrefix); err != nil {
76			return err
77		}
78	
79		// Fetch the controllerconfig
80		cc, err := ctrl.ccLister.Get(ctrlcommon.ControllerConfigName)
81		if err != nil {
82			return fmt.Errorf("could not get ControllerConfig, err: %w", err)
83		}
84		// Find all MachineConfigPools
85		mcpPools, err := ctrl.mcpLister.List(labels.Everything())
86		if err != nil {
87			return err
88		}
89	
90		// Grab APIServer to populate TLS settings in the default kubelet config
91		apiServer, err := ctrl.apiserverLister.Get(ctrlcommon.APIServerInstanceName)
92		if err != nil && !errors.IsNotFound(err) {
93			return fmt.Errorf("could not get the TLSSecurityProfile from %v: %w", ctrlcommon.APIServerInstanceName, err)
94		}
95	
96		for _, pool := range mcpPools {
97			role := pool.Name
98			// Get MachineConfig
99			key, err := getManagedNodeConfigKey(pool, ctrl.client)
100			if err != nil {
101				return err
102			}
103			mc, err := ctrl.client.MachineconfigurationV1().MachineConfigs().Get(context.TODO(), key, metav1.GetOptions{})
104			isNotFound := errors.IsNotFound(err)
105			if err != nil && !isNotFound {
106				return err
107			}
108			if isNotFound {
109				ignConfig := ctrlcommon.NewIgnConfig()
110				mc, err = ctrlcommon.MachineConfigFromIgnConfig(role, key, ignConfig)
111				if err != nil {
112					return err
113				}
114			}
115			originalKubeConfig, err := generateOriginalKubeletConfigWithFeatureGates(cc, ctrl.templatesDir, role, ctrl.fgHandler, apiServer)
116			if err != nil {
117				return err
118			}
119			// the workerlatencyprofile's configuration change will be applied only on the worker nodes.
120			if role == ctrlcommon.MachineConfigPoolWorker {
121				// updating the kubelet configuration with the Node specific configuration.
122				err = updateOriginalKubeConfigwithNodeConfig(nodeConfig, originalKubeConfig)
123				if err != nil {
124					return err
125				}
126			}
127			// The following code updates the MC with the relevant CGroups version
128			switch role {
129			case ctrlcommon.MachineConfigPoolWorker, ctrlcommon.MachineConfigPoolMaster, ctrlcommon.MachineConfigPoolArbiter:
130				err = updateMachineConfigwithCgroup(nodeConfig, mc)
131				if err != nil {
132					return err
133				}
134			}
135			// Encode the new config into raw JSON
136			cfgIgn, err := kubeletConfigToIgnFile(originalKubeConfig)
137			if err != nil {
138				return err
139			}
140			tempIgnConfig := ctrlcommon.NewIgnConfig()
141			tempIgnConfig.Storage.Files = append(tempIgnConfig.Storage.Files, *cfgIgn)
142			rawCfgIgn, err := json.Marshal(tempIgnConfig)
143			if err != nil {
144				return err
145			}
146			mc.Spec.Config.Raw = rawCfgIgn
147			mc.ObjectMeta.Annotations = map[string]string{
148				ctrlcommon.GeneratedByControllerVersionAnnotationKey: version.Hash,
149			}
150			// Create or Update, on conflict retry
151			if err := retry.RetryOnConflict(updateBackoff, func() error {
152				var err error
153				if isNotFound {
154					_, err = ctrl.client.MachineconfigurationV1().MachineConfigs().Create(context.TODO(), mc, metav1.CreateOptions{})
155				} else {
156					_, err = ctrl.client.MachineconfigurationV1().MachineConfigs().Update(context.TODO(), mc, metav1.UpdateOptions{})
157				}
158				return err
159			}); err != nil {
160				return fmt.Errorf("could not Create/Update MachineConfig, error: %w", err)
161			}
162			klog.Infof("Applied Node configuration %v on MachineConfigPool %v", key, pool.Name)
163			ctrlcommon.UpdateStateMetric(ctrlcommon.MCCSubControllerState, "machine-config-controller-kubelet-config", "Sync NodeConfig", pool.Name)
164		}
165		// fetch the kubeletconfigs
166		kcs, err := ctrl.mckLister.List(labels.Everything())
167		if err != nil {
168			return fmt.Errorf("could not get KubeletConfigs, err: %w", err)
169		}
170		for _, kc := range kcs {
171			// updating the existing kubeletconfigs with the updated nodeconfig
172			err := ctrl.syncKubeletConfig(kc.Name)
173			if err != nil {
174				return fmt.Errorf("could not update KubeletConfig %v, err: %w", kc, err)
175			}
176		}
177	
178		// syncing the featuregate controller
179		features, err := ctrl.featLister.Get(ctrlcommon.ClusterFeatureInstanceName)
180		if err == nil {
181			err := ctrl.syncFeatureHandler(features.Name)
182			if err != nil {
183				return fmt.Errorf("could not sync featuregate controller %v, err: %w", features, err)
184			}
185		}
186		return nil
187	}
