189	func (ctrl *Controller) enqueueNodeConfig(nodeConfig *osev1.Node) {
190		key, err := cache.DeletionHandlingMetaNamespaceKeyFunc(nodeConfig)
191		if err != nil {
192			utilruntime.HandleError(fmt.Errorf("couldn't get key for object %#v: %w", nodeConfig, err))
193			return
194		}
195		ctrl.nodeConfigQueue.Add(key)
196	}
