198	func (ctrl *Controller) updateNodeConfig(old, cur interface{}) {
199		isValidWorkerLatencyProfleTransition := true
200		oldNode, ok := old.(*osev1.Node)
201		if !ok {
202			utilruntime.HandleError(fmt.Errorf("couldn't retrieve the old object from the Update Node Config event %#v", old))
203			return
204		}
205		newNode, ok := cur.(*osev1.Node)
206		if !ok {
207			utilruntime.HandleError(fmt.Errorf("couldn't retrieve the new object from the Update Node Config event %#v", cur))
208			return
209		}
210		if newNode.Name != ctrlcommon.ClusterNodeInstanceName {
211			message := fmt.Sprintf("The node.config.openshift.io \"%v\" is invalid: metadata.name Invalid value: \"%v\" : must be \"%v\"", newNode.Name, newNode.Name, ctrlcommon.ClusterNodeInstanceName)
212			ctrl.eventRecorder.Eventf(oldNode, corev1.EventTypeNormal, "ActionProhibited", message)
213			klog.V(2).Infof("%s", message)
214			return
215		}
216		if !reflect.DeepEqual(oldNode.Spec, newNode.Spec) {
217			// skipping the update in case of the Worker-Latency-Profile type transition from "Default" to "LowUpdateSlowReaction" and vice-versa
218			// (TODO) Ideally the user request has to be honoured, the transition need to be from Default -> Medium -> Low or vice-versa.
219			// Restricting the request for now until this process is automated in future.
220			if oldNode.Spec.WorkerLatencyProfile == osev1.LowUpdateSlowReaction {
221				if newNode.Spec.WorkerLatencyProfile == osev1.DefaultUpdateDefaultReaction || newNode.Spec.WorkerLatencyProfile == "" {
222					isValidWorkerLatencyProfleTransition = false
223				}
224			}
225			if newNode.Spec.WorkerLatencyProfile == osev1.LowUpdateSlowReaction {
226				if oldNode.Spec.WorkerLatencyProfile == osev1.DefaultUpdateDefaultReaction || oldNode.Spec.WorkerLatencyProfile == "" {
227					isValidWorkerLatencyProfleTransition = false
228				}
229			}
230			if !isValidWorkerLatencyProfleTransition {
231				message := fmt.Sprintf("Skipping the Update Node event, name: %s, transition not allowed from old WorkerLatencyProfile: \"%s\" to new WorkerLatencyProfile: \"%s\"", newNode.Name, oldNode.Spec.WorkerLatencyProfile, newNode.Spec.WorkerLatencyProfile)
232				ctrl.eventRecorder.Eventf(newNode, corev1.EventTypeNormal, "ActionProhibited", message)
233				klog.Info(message)
234				return
235			}
236			klog.V(4).Infof("Updating the node config resource, name: %s", newNode.Name)
237			ctrl.enqueueNodeConfig(newNode)
238		}
239	}
