241	func (ctrl *Controller) addNodeConfig(obj interface{}) {
242		nodeConfig, ok := obj.(*osev1.Node)
243		if !ok {
244			utilruntime.HandleError(fmt.Errorf("couldn't retrieve the object from the Add Node Config event %#v", obj))
245			return
246		}
247		if nodeConfig.Name != ctrlcommon.ClusterNodeInstanceName {
248			message := fmt.Sprintf("The node.config.openshift.io \"%v\" is invalid: metadata.name Invalid value: \"%v\" : must be \"%v\"", nodeConfig.Name, nodeConfig.Name, ctrlcommon.ClusterNodeInstanceName)
249			klog.V(2).Info(message)
250			ctrl.eventRecorder.Eventf(nodeConfig, corev1.EventTypeNormal, "ActionProhibited", message)
251			return
252		}
253		klog.V(4).Infof("Adding the node config resource, name: %s", nodeConfig.Name)
254		ctrl.enqueueNodeConfig(nodeConfig)
255	}
