257	func (ctrl *Controller) deleteNodeConfig(obj interface{}) {
258		nodeConfig, ok := obj.(*osev1.Node)
259		if !ok {
260			tombstone, ok := obj.(cache.DeletedFinalStateUnknown)
261			if !ok {
262				utilruntime.HandleError(fmt.Errorf("couldn't get object from tombstone %#v", obj))
263				return
264			}
265			nodeConfig, ok = tombstone.Obj.(*osev1.Node)
266			if !ok {
267				utilruntime.HandleError(fmt.Errorf("tombstone contained object that is not a NodeConfig %#v", obj))
268				return
269			}
270		}
271		klog.V(4).Infof("Deleted node config %s and restored default config", nodeConfig.Name)
272	}
